external_knowledge:
- Environmentally friendly IC components are those that are lead-free; 
- "In stock" refers to the quantity of the IC component being greater than zero;
- "Unique identifiers" correspond to the part numbers of the components.

sql:
SELECT o.part_number, o.status
FROM orders o
INNER JOIN ic_components ic ON o.part_number = ic.part_number;

SELECT SUM(quantity) AS total_quantity_pending
FROM orders
WHERE status = 'Pending' AND strftime('%Y', order_date) = '2023';

SELECT AVG(leads) AS average_lead_count
FROM ic_components ic
WHERE ic.is_eol = 0 AND ic.lead_free = 0 AND ic.leads > 20;

SELECT part_number
FROM ic_components
WHERE part_number NOT IN (SELECT part_number FROM inventory);

SELECT part_number
FROM ic_components
WHERE leads = (SELECT MIN(leads) FROM ic_components);

external_knowledge:
- "not outdated" refers to IC components that are not marked as end-of-life (EOL);
- "environmentally friendly" refers to components that are lead-free and RoHS compliant;
- "current stock information" includes quantity in stock, location, and related inventory details;
- "recent orders placed" includes order details like quantity, supplier, delivery information, and payment status.

sql:
SELECT COUNT(part_number) 
FROM ic_components 
WHERE lead_free = 1 AND rohs_compliant = 1 AND is_eol = 1;

SELECT part_number
FROM inventory
WHERE quantity > 0;

SELECT ic_components.part_number, inventory.quantity, inventory.warehouse_location
FROM ic_components
JOIN inventory ON ic_components.part_number = inventory.part_number;

